import{_ as p,o as a,c as t,ak as o}from"./chunks/framework.aEAtsvX-.js";const u=JSON.parse('{"title":"区块漏斗","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/upgradeable_hoppers.md","filePath":"plugins/upgradeable_hoppers.md","lastUpdated":1776083463000}'),r={name:"plugins/upgradeable_hoppers.md"};function s(c,e,l,d,n,i){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="区块漏斗" tabindex="-1">区块漏斗 <a class="header-anchor" href="#区块漏斗" aria-label="Permalink to “区块漏斗”">​</a></h1><div class="tip custom-block"><p class="custom-block-title">提示</p><p>使用<code>/uhoppers help</code>获得这个插件的命令的用法。</p></div><p><strong>Upgradeable Hoppers</strong> 是一个 Minecraft 服务器插件（Spigot/Bukkit），其核心功能是<strong>用单个高性能漏斗替代复杂的漏斗链</strong>，从而大幅减少服务器因实体漏斗产生的 Tick 延迟（TPS Lag）。</p><p>漏斗可以自动拾取整个区块内掉落在地面上的物品，无需使用水流或漏斗矿车收集。</p><p>由于是测试，价格会进行调整，不是最终结果。</p><p>只能在自己的领土或被信任的领土中使用。领土中被信任的其他人或领土拥有者可以编辑区块漏斗的设置。</p><p>查看管理已放置的升级漏斗命令:<code>/uhoppers list</code></p><p>购买漏斗命令:<code>/uhoppers get</code> 默认normal或chunk。</p><p>左键升级漏斗打开交互菜单，右键打开漏斗，可潜行时用工具破坏回收已放置的升级漏斗。</p>',9)])])}const g=p(r,[["render",s]]);export{u as __pageData,g as default};
